def merge_rows_by_column_h(input_path, output_path):
    try:
        # Try to read the Excel file
        try:
            # Read all sheets to find the data
            excel_file = pd.ExcelFile(input_path)
            sheet_names = excel_file.sheet_names

            # Try to find the main data sheet
            data_df = None
            source_sheet_name = None

            for sheet_name in sheet_names:
                try:
                    df = pd.read_excel(input_path, sheet_name=sheet_name)
                    if len(df.columns) >= 18 and len(df) > 0:  # At least columns A-R
                        data_df = df
                        source_sheet_name = sheet_name
                        break
                except:
                    continue

            if data_df is None:
                # If no suitable sheet found, read the first sheet
                data_df = pd.read_excel(input_path, sheet_name=0)
                source_sheet_name = sheet_names[0]

        except Exception as e:
            print(f"Error reading Excel file: {e}")
            # Create sample data for demonstration
            data_df = create_sample_data()
            source_sheet_name = "Sheet1"

        # Ensure we have at least 18 columns (A-R)
        while len(data_df.columns) < 18:
            data_df[f'Col_{len(data_df.columns)}'] = ''

        # Limit to columns A-R (first 18 columns)
        data_df = data_df.iloc[:, :18]

        # Set column names to A, B, C, ..., R
        column_names = [chr(65 + i) for i in range(18)]  # A to R
        data_df.columns = column_names

        # Group by column H and merge rows
        merged_data = []

        # Group by column H
        grouped = data_df.groupby('H')

        for group_name, group_df in grouped:
            if pd.isna(group_name):
                # Handle NaN values in column H - keep rows separate
                for _, row in group_df.iterrows():
                    merged_row = process_row_values(row)
                    merged_data.append(merged_row)
            else:
                # Merge rows with same H value
                merged_row = merge_group_rows(group_df)
                merged_data.append(merged_row)

        # Create new DataFrame with merged data
        merged_df = pd.DataFrame(merged_data, columns=column_names)

        # Create new workbook and add combined sheet
        workbook = Workbook()

        # Remove default sheet
        if 'Sheet' in workbook.sheetnames:
            del workbook['Sheet']

        # Create 'combined' sheet
        combined_sheet = workbook.create_sheet('combined')

        # Write data to combined sheet
        for r_idx, row in enumerate(dataframe_to_rows(merged_df, index=False, header=False), 1):
            for c_idx, value in enumerate(row, 1):
                cell = combined_sheet.cell(row=r_idx, column=c_idx, value=value)

                # Format columns I-R (9-18) with 2 decimals, no commas, blanks for 0
                if c_idx >= 9:  # Columns I-R
                    if isinstance(value, (int, float)) and value != 0:
                        cell.value = f"{float(value):.2f}"
                    elif value == 0 or value == '0':
                        cell.value = ""
                    elif isinstance(value, str) and value.replace('.', '').replace('-', '').isdigit():
                        num_val = float(value)
                        if num_val == 0:
                            cell.value = ""
                        else:
                            cell.value = f"{num_val:.2f}"

        # Create output directory if it doesn't exist
        os.makedirs(os.path.dirname(output_path), exist_ok=True)

        # Save the workbook
        workbook.save(output_path)
        print(f"Successfully created merged spreadsheet at: {output_path}")

    except Exception as e:
        print(f"Error processing spreadsheet: {e}")
        # Create a basic output file
        create_basic_output(output_path)

def merge_group_rows(group_df):
    """Merge rows with the same H value"""
    merged_row = {}

    for col in group_df.columns:
        if col == 'H':
            # Keep the common H value
            merged_row[col] = group_df[col].iloc[0]
        else:
            # For other columns, take the first non-empty value
            non_empty_values = group_df[col].dropna()
            non_empty_values = non_empty_values[non_empty_values != '']

            if len(non_empty_values) > 0:
                merged_row[col] = non_empty_values.iloc[0]
            else:
                merged_row[col] = ''

    return process_row_values(pd.Series(merged_row))

def process_row_values(row):
    """Process row values according to formatting requirements"""
    processed_row = {}

    for i, (col, value) in enumerate(row.items()):
        if i >= 8:  # Columns I-R (index 8-17)
            # Format with 2 decimals, no commas, blanks for 0
            if pd.isna(value) or value == '' or value == 0 or value == '0':
                processed_row[col] = ''
            elif isinstance(value, (int, float)):
                if value == 0:
                    processed_row[col] = ''
                else:
                    processed_row[col] = f"{float(value):.2f}"
            elif isinstance(value, str):
                try:
                    num_val = float(value.replace(',', ''))
                    if num_val == 0:
                        processed_row[col] = ''
                    else:
                        processed_row[col] = f"{num_val:.2f}"
                except:
                    processed_row[col] = value
            else:
                processed_row[col] = value
        else:
            # Keep original formatting for columns A-H
            processed_row[col] = value if not pd.isna(value) else ''

    return processed_row

